arguments.content:
# Qwen Proxy 测试脚本

Write-Host "`n========================================" -ForegroundColor Cyan
Write-Host "  Qwen Proxy 测试" -ForegroundColor Cyan
Write-Host "========================================`n" -ForegroundColor Cyan

# 1. 健康检查
Write-Host "[1] 健康检查..." -NoNewline
try {
    $health = (New-Object System.Net.WebClient).DownloadString("http://localhost:3000/health")
    Write-Host " ✅ OK" -ForegroundColor Green
    Write-Host "    $health`n"
} catch {
    Write-Host " ❌ FAILED" -ForegroundColor Red
    Write-Host "    $_`n"
}

# 2. 模型列表
Write-Host "[2] 模型列表..." -NoNewline
try {
    $models = (New-Object System.Net.WebClient).DownloadString("http://localhost:3000/v1/models")
    Write-Host " ✅ OK" -ForegroundColor Green
    $modelList = $models | ConvertFrom-Json | Select-Object -ExpandProperty data | Select-Object -ExpandProperty id
    foreach ($m in $modelList) {
        Write-Host "    - $m"
    }
    Write-Host ""
} catch {
    Write-Host " ❌ FAILED" -ForegroundColor Red
    Write-Host "    $_`n"
}

# 3. Responses API 测试
Write-Host "[3] Responses API 测试..." -NoNewline
try {
    $body = @{model="qwen3.5-plus";input="用一句话回复：测试成功"} | ConvertTo-Json -Depth 5
    $wc = New-Object System.Net.WebClient
    $wc.Headers["Content-Type"] = "application/json"
    $response = $wc.UploadString("http://localhost:3000/v1/responses", $body)
    $result = $response | ConvertFrom-Json
    Write-Host " ✅ OK" -ForegroundColor Green
    Write-Host "    响应：$($result.output)`n"
} catch {
    Write-Host " ❌ FAILED" -ForegroundColor Red
    Write-Host "    $_`n"
}

# 4. Chat Completions API 测试
Write-Host "[4] Chat Completions API 测试..." -NoNewline
try {
    $body = @{
        model="qwen3.5-plus"
        messages=@(@{role="user";content="用一句话回复：测试成功"})
    } | ConvertTo-Json -Depth 5
    $wc = New-Object System.Net.WebClient
    $wc.Headers["Content-Type"] = "application/json"
    $response = $wc.UploadString("http://localhost:3000/v1/chat/completions", $body)
    $result = $response | ConvertFrom-Json
    $content = $result.choices[0].message.content
    Write-Host " ✅ OK" -ForegroundColor Green
    Write-Host "    响应：$content`n"
} catch {
    Write-Host " ❌ FAILED" -ForegroundColor Red
    Write-Host "    $_`n"
}

Write-Host "========================================" -ForegroundColor Cyan
Write-Host "  测试完成" -ForegroundColor Cyan
Write-Host "========================================`n" -ForegroundColor Cyan
